;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4, 5]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@se f=kacha
@wait time=800
@se f=fence
@switchfence x=3 y=2 way=s mode=open
@wait time=800
@notice text="I heard a door open somewhere!"
@delevent

[eventoff]
